const items = [];
const item = $input.first();
const binaryKeys = Object.keys(item.binary || {});

for (let i = 0; i < binaryKeys.length; i++) {
  const key = binaryKeys[i];
  const bin = item.binary[key];
  const isPdf =
    bin.mimeType === 'application/pdf' ||
    bin.fileName?.toLowerCase().endsWith('.pdf') ||
    key.toLowerCase().includes('pdf');

  if (isPdf) {
    items.push({
      json: {
        messageId: item.json.id,
        emailSubject: item.json.subject || '',
        emailDate: item.json.date || new Date().toISOString(),
        emailFrom: item.json.from || '',
        fileName: bin.fileName || `extrato_${Date.now()}.pdf`,
        binaryKey: key
      },
      binary: { data: bin }
    });
  }
}

if (items.length === 0) {
  return [{ json: { skip: true, messageId: item.json.id } }];
}

return items;

