// Sanitiza e normaliza o JSON retornado pelo LLM Chain
const item = $input.first();

// Basic LLM Chain retorna em item.json.text
const raw = item.json?.text ||
            item.json?.output ||
            item.json?.response ||
            '';

if (!raw) {
  throw new Error('LLM não retornou conteúdo. Response: ' + JSON.stringify(item.json));
}

// Remove markdown fences
const clean = raw
  .replace(/```json\s*/gi, '')
  .replace(/```\s*/g, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(clean);
} catch(e) {
  throw new Error(`LLM retornou JSON inválido.\nRaw: ${raw}\nErro: ${e.message}`);
}

// Normaliza numéricos (vírgula BR → ponto)
const numFields = [
  'aluguel_bruto','energia','iptu_valor','taxa_administracao',
  'total_credito','total_debito','valor_liquido'
];
for (const f of numFields) {
  if (typeof parsed[f] === 'string') {
    parsed[f] = parseFloat(parsed[f].replace(/\./g,'').replace(',','.')) || 0;
  }
  if (parsed[f] === undefined || parsed[f] === null) parsed[f] = 0;
}

// Normaliza datas DD/MM/AAAA → AAAA-MM-DD
const dateFields = [
  'vencimento_aluguel','pagamento_aluguel','data_pagamento_efetivo',
  'reajuste','termino_contrato','periodo_inicio','periodo_fim'
];
for (const f of dateFields) {
  if (parsed[f] && parsed[f] !== 'null') {
    const p = parsed[f].split('/');
    if (p.length === 3) parsed[f] = `${p[2]}-${p[1]}-${p[0]}`;
  } else {
    parsed[f] = null;
  }
}

// Chave de deduplicação
parsed.chave_unica = `${parsed.contrato}_parcela${parsed.parcela}`;

// Metadados do email
parsed.email_messageId = $('Code — Filtrar PDFs').first().json.messageId || '';
parsed.email_fileName  = $('Code — Filtrar PDFs').first().json.fileName  || '';
parsed.email_date      = $('Code — Filtrar PDFs').first().json.emailDate || '';

return [{ json: parsed }];

// Extrai apenas anexos PDF do email
const items = [];
const item = $input.first();
const binaryKeys = Object.keys(item.binary || {});

for (let i = 0; i < binaryKeys.length; i++) {
  const key = binaryKeys[i];
  const bin = item.binary[key];
  const isPdf =
    bin.mimeType === 'application/pdf' ||
    bin.fileName?.toLowerCase().endsWith('.pdf') ||
    key.toLowerCase().includes('pdf');

  if (isPdf) {
    items.push({
      json: {
        messageId: item.json.id,
        emailSubject: item.json.subject || '',
        emailDate: item.json.date || new Date().toISOString(),
        emailFrom: item.json.from || '',
        fileName: bin.fileName || `extrato_${Date.now()}.pdf`,
        binaryKey: key
      },
      binary: { data: bin }
    });
  }
}

if (items.length === 0) {
  return [{ json: { skip: true, messageId: item.json.id } }];
}

return items;

